public class ImageNegation {
 public static byte[] negateImage(byte[] image) {
 byte maxIntensity = (byte) 255;
 byte[] negatedImage = new byte[image.length];
 for (int i = 0; i < image.length; i++) {
 negatedImage[i] = (byte) (maxIntensity - image[i]);
 }
 return negatedImage;
 }
}
